// Streaming tok/s benchmark for the gnosis OpenAI-compatible mesh.
//   node bench-mesh-tps.mjs <BASE_URL> <model1> [model2 ...]
// e.g. node bench-mesh-tps.mjs https://q4ktest---gnosis-openai-mesh-...run.app \
//        qwen3-8b qwen3-8b-q4k qwen3-4b qwen3-4b-q4k gemma3-4b-it gemma3-4b-it-q4k
// For each model: one warm-up request (discarded), then a measured run.
// Reports: prefill (time-to-first-token) and DECODE tok/s (tokens after the
// first, divided by first->last wall time) — the honest "tok/sec" number.
// Built to A/B Q8 vs Q4_K knot variants (decode ~parity; Q4_K wins size/load,
// not tok/s — knots live in forkjoin-ai/<model>-gguf next to the gguf).
const BASE = process.argv[2];
const MODELS = process.argv.slice(3);
const PROMPT = 'Write three sentences about the city of Paris and why people visit it.';
const MAX_TOKENS = 64;

async function run(model, { warm }) {
  const t0 = Date.now();
  let firstAt = 0, lastAt = 0, toks = 0;
  const res = await fetch(`${BASE}/v1/chat/completions`, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({
      model, stream: true, max_tokens: MAX_TOKENS, temperature: 0,
      messages: [{ role: 'user', content: PROMPT }],
    }),
  });
  if (!res.ok) return { model, error: `HTTP ${res.status} ${(await res.text()).slice(0, 200)}` };
  const reader = res.body.getReader();
  const dec = new TextDecoder();
  let buf = '';
  for (;;) {
    const { done, value } = await reader.read();
    if (done) break;
    buf += dec.decode(value, { stream: true });
    let i;
    while ((i = buf.indexOf('\n')) >= 0) {
      const line = buf.slice(0, i).trim(); buf = buf.slice(i + 1);
      if (!line.startsWith('data:')) continue;
      const data = line.slice(5).trim();
      if (data === '[DONE]') continue;
      try {
        const j = JSON.parse(data);
        const piece = j.choices?.[0]?.delta?.content ?? j.choices?.[0]?.text ?? '';
        if (piece) { const now = Date.now(); if (!firstAt) firstAt = now; lastAt = now; toks++; }
      } catch {}
    }
  }
  const prefillMs = firstAt ? firstAt - t0 : 0;
  const decodeMs = firstAt && lastAt > firstAt ? lastAt - firstAt : 0;
  const decodeToks = Math.max(0, toks - 1);
  const decodeTps = decodeMs > 0 ? (decodeToks / (decodeMs / 1000)) : 0;
  return { model, warm, toks, prefillMs, decodeMs, decodeTps: +decodeTps.toFixed(2) };
}

for (const m of MODELS) {
  try {
    await run(m, { warm: 'warmup' });               // discard
    const r = await run(m, { warm: 'measured' });
    if (r.error) console.log(`${m.padEnd(20)} ERROR ${r.error}`);
    else console.log(`${m.padEnd(20)} decode ${String(r.decodeTps).padStart(6)} tok/s  | prefill(ttft) ${r.prefillMs}ms | ${r.toks} toks`);
  } catch (e) {
    console.log(`${m.padEnd(20)} EXC ${e.message}`);
  }
}
